import type { ReactNode } from 'react';

import { type Href } from 'expo-router';
import { Pressable, Text, View } from 'react-native';
import {
  KangurMobileActionButton as MobileActionButton,
  KangurMobileCard as MobileCard,
  KangurMobileLinkButton as MobileLinkButton,
  KangurMobilePill as MobilePill,
} from './KangurMobileUi';

export type Tone = {
  backgroundColor: string;
  borderColor: string;
  textColor: string;
};

export const BASE_TONE: Tone = {
  backgroundColor: '#f8fafc',
  borderColor: '#cbd5e1',
  textColor: '#475569',
};

export const SUCCESS_TONE: Tone = {
  backgroundColor: '#ecfdf5',
  borderColor: '#a7f3d0',
  textColor: '#047857',
};

export const WARNING_TONE: Tone = {
  backgroundColor: '#fffbeb',
  borderColor: '#fde68a',
  textColor: '#b45309',
};

export const INDIGO_TONE: Tone = {
  backgroundColor: '#eef2ff',
  borderColor: '#c7d2fe',
  textColor: '#4338ca',
};

export function ChoiceCardButton({
  description,
  disabled = false,
  helperText,
  indexLabel,
  label,
  onPress,
  tone = BASE_TONE,
}: {
  description?: string;
  disabled?: boolean;
  helperText?: ReactNode;
  indexLabel: string;
  label: string;
  onPress: () => void;
  tone?: Tone;
}): React.JSX.Element {
  return (
    <Pressable
      accessibilityRole='button'
      disabled={disabled}
      onPress={onPress}
      style={{
        backgroundColor: tone.backgroundColor,
        borderColor: tone.borderColor,
        borderRadius: 20,
        borderWidth: 1,
        gap: 8,
        opacity: disabled ? 0.8 : 1,
        paddingHorizontal: 16,
        paddingVertical: 14,
      }}
    >
      <View
        style={{
          alignItems: 'center',
          flexDirection: 'row',
          gap: 10,
        }}
      >
        <View
          style={{
            alignItems: 'center',
            backgroundColor: '#ffffff',
            borderColor: tone.borderColor,
            borderRadius: 999,
            borderWidth: 1,
            height: 28,
            justifyContent: 'center',
            width: 28,
          }}
        >
          <Text style={{ color: '#0f172a', fontWeight: '800' }}>{indexLabel}</Text>
        </View>
        <Text
          style={{
            color: '#0f172a',
            flex: 1,
            fontSize: 15,
            fontWeight: '700',
          }}
        >
          {label}
        </Text>
      </View>
      {description ? (
        <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>{description}</Text>
      ) : null}
      {helperText}
    </Pressable>
  );
}

export function SectionCard({
  children,
  title,
}: {
  children: React.ReactNode;
  title: string;
}): React.JSX.Element {
  return (
    <MobileCard gap={12} padding={20}>
      <Text
        accessibilityRole='header'
        style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}
      >
        {title}
      </Text>
      {children}
    </MobileCard>
  );
}

export function StatusPill({
  label,
  tone = BASE_TONE,
}: {
  label: string;
  tone?: Tone;
}): React.JSX.Element {
  return (
    <MobilePill
      label={label}
      style={{ paddingHorizontal: 10, paddingVertical: 6 }}
      textStyle={{ fontSize: 12 }}
      tone={tone}
    />
  );
}

export function OutlineLink({
  href,
  hint,
  label,
}: {
  href: Href;
  hint?: string;
  label: string;
}): React.JSX.Element {
  return (
    <MobileLinkButton
      accessibilityHint={hint}
      accessibilityLabel={label}
      href={href}
      label={label}
      stretch
      tone='secondary'
    />
  );
}

export function PrimaryButton({
  disabled = false,
  hint,
  label,
  onPress,
  tone = INDIGO_TONE,
}: {
  disabled?: boolean;
  hint?: string;
  label: string;
  onPress?: () => void;
  tone?: Tone;
}): React.JSX.Element {
  return (
    <MobileActionButton
      accessibilityHint={hint}
      accessibilityLabel={label}
      centered
      disabled={disabled}
      label={label}
      minHeight={44}
      onPress={onPress ?? (() => {})}
      stretch
      style={{
        backgroundColor: disabled ? '#e2e8f0' : tone.backgroundColor,
        borderColor: disabled ? '#cbd5e1' : tone.borderColor,
        opacity: disabled ? 0.7 : 1,
        paddingHorizontal: 16,
      }}
      textStyle={{
        color: disabled ? '#64748b' : tone.textColor,
      }}
      tone='secondary'
    />
  );
}

import { Link, type Href } from 'expo-router';
import {
  Pressable,
  Text,
  type StyleProp,
  type TextStyle,
  type ViewStyle,
} from 'react-native';

export type KangurMobileActionButtonProps = {
  accessibilityHint?: string;
  accessibilityLabel?: string;
  borderRadius?: number;
  centered?: boolean;
  disabledOpacity?: number;
  disabled?: boolean;
  horizontalPadding?: number;
  label: string;
  minHeight?: number;
  onPress: () => void | Promise<void>;
  stretch?: boolean;
  style?: StyleProp<ViewStyle>;
  textStyle?: StyleProp<TextStyle>;
  tone?: 'brand' | 'ghost' | 'primary' | 'secondary';
  verticalPadding?: number;
};

export type KangurMobileLinkButtonProps = {
  accessibilityHint?: string;
  accessibilityLabel?: string;
  borderRadius?: number;
  centered?: boolean;
  href: Href;
  label: string;
  minHeight?: number;
  onPress?: () => void;
  stretch?: boolean;
  style?: StyleProp<ViewStyle>;
  textStyle?: StyleProp<TextStyle>;
  tone?: 'brand' | 'primary' | 'secondary';
  verticalPadding?: number;
};

export type KangurMobilePendingActionButtonProps = {
  accessibilityLabel?: string;
  horizontalPadding?: number;
  label: string;
  onPress: () => void | Promise<void>;
  pending: boolean;
  pendingLabel: string;
  stretch?: boolean;
  verticalPadding?: number;
};

const getButtonBorderColor = (tone: string): string => {
  if (tone === 'primary' || tone === 'brand') return 'transparent';
  if (tone === 'ghost') return '#e2e8f0';
  return '#cbd5e1';
};

const getButtonBackgroundColor = (tone: string): string => {
  if (tone === 'primary') return '#0f172a';
  if (tone === 'brand') return '#1d4ed8';
  return '#ffffff';
};

const getButtonOpacity = (disabled: boolean, disabledOpacity: number): number => 
  disabled ? disabledOpacity : 1;

const getButtonBorderWidth = (tone: 'brand' | 'ghost' | 'primary' | 'secondary'): number => 
  tone === 'primary' || tone === 'brand' ? 0 : 1;

const getButtonAlignSelf = (stretch: boolean): 'flex-start' | 'stretch' =>
  stretch ? 'stretch' : 'flex-start';

const getButtonWidth = (stretch: boolean): '100%' | undefined =>
  stretch ? '100%' : undefined;

const getButtonFlexAlignment = (centered: boolean): 'center' | undefined =>
  centered ? 'center' : undefined;

const getButtonBoxStyle = (
  tone: 'brand' | 'ghost' | 'primary' | 'secondary',
): { borderWidth: number; borderColor: string; backgroundColor: string } => ({
  borderWidth: getButtonBorderWidth(tone),
  borderColor: getButtonBorderColor(tone),
  backgroundColor: getButtonBackgroundColor(tone),
});

const getButtonLayoutPadding = (
  horizontalPadding: number,
  verticalPadding: number,
): { paddingHorizontal: number; paddingVertical: number } => ({
  paddingHorizontal: horizontalPadding,
  paddingVertical: verticalPadding,
});

type ResolvedButtonBaseProps = {
  borderRadius: number;
  centered: boolean;
  disabledOpacity: number;
  disabled: boolean;
  horizontalPadding: number;
  stretch: boolean;
  tone: 'brand' | 'ghost' | 'primary' | 'secondary';
  verticalPadding: number;
};

const DEFAULT_BUTTON_BASE_PROPS: ResolvedButtonBaseProps = {
  borderRadius: 999,
  centered: false,
  disabledOpacity: 0.55,
  disabled: false,
  horizontalPadding: 14,
  stretch: false,
  tone: 'secondary',
  verticalPadding: 10,
};

const resolveButtonBaseProps = (params: {
  borderRadius?: number;
  centered?: boolean;
  disabledOpacity?: number;
  disabled?: boolean;
  horizontalPadding?: number;
  minHeight?: number;
  stretch?: boolean;
  tone?: 'brand' | 'ghost' | 'primary' | 'secondary';
  verticalPadding?: number;
}): ResolvedButtonBaseProps => ({
  ...DEFAULT_BUTTON_BASE_PROPS,
  ...params,
} as ResolvedButtonBaseProps);

export const getButtonContainerStyle = (params: {
  borderRadius?: number;
  centered?: boolean;
  disabledOpacity?: number;
  disabled?: boolean;
  horizontalPadding?: number;
  minHeight?: number;
  stretch?: boolean;
  tone?: 'brand' | 'ghost' | 'primary' | 'secondary';
  verticalPadding?: number;
}): ViewStyle => {
  const base = resolveButtonBaseProps(params);
  const box = getButtonBoxStyle(base.tone);
  const layout = getButtonLayoutPadding(
    base.horizontalPadding,
    base.verticalPadding,
  );

  const containerStyle: ViewStyle = {
    alignSelf: getButtonAlignSelf(base.stretch),
    width: getButtonWidth(base.stretch),
    opacity: getButtonOpacity(base.disabled, base.disabledOpacity),
    borderRadius: base.borderRadius,
    borderWidth: box.borderWidth,
    borderColor: box.borderColor,
    backgroundColor: box.backgroundColor,
  };

  containerStyle.alignItems = getButtonFlexAlignment(base.centered);
  containerStyle.justifyContent = getButtonFlexAlignment(base.centered);
  containerStyle.minHeight = params.minHeight;
  containerStyle.paddingHorizontal = layout.paddingHorizontal;
  containerStyle.paddingVertical = layout.paddingVertical;

  return containerStyle;
};

export const getButtonTextStyle = (
  centered: boolean,
  tone: 'brand' | 'ghost' | 'primary' | 'secondary',
  stretch: boolean,
): TextStyle => ({
  color: tone === 'primary' || tone === 'brand' ? '#ffffff' : '#0f172a',
  fontWeight: '700',
  textAlign: centered || stretch ? 'center' : 'left',
});

export function KangurMobileActionButton(
  props: KangurMobileActionButtonProps,
): React.JSX.Element {
  const {
    accessibilityHint,
    disabled = false,
    accessibilityLabel,
    borderRadius,
    centered = false,
    disabledOpacity,
    horizontalPadding,
    label,
    minHeight,
    onPress,
    stretch = false,
    style,
    textStyle,
    tone = 'primary',
    verticalPadding = 10,
  } = props;

  return (
    <Pressable
      accessibilityRole='button'
      accessibilityHint={accessibilityHint}
      accessibilityLabel={accessibilityLabel}
      disabled={disabled}
      onPress={() => {

        void onPress();
      }}
      style={[
        getButtonContainerStyle({
          borderRadius,
          centered,
          disabledOpacity,
          disabled,
          horizontalPadding,
          minHeight,
          stretch,
          tone,
          verticalPadding,
        }),
        style,
      ]}
    >
      <Text style={[getButtonTextStyle(centered, tone, stretch), textStyle]}>{label}</Text>
    </Pressable>
  );
}

export function KangurMobileLinkButton(props: KangurMobileLinkButtonProps): React.JSX.Element {
  const {
    href,
    accessibilityHint,
    accessibilityLabel,
    borderRadius,
    centered = false,
    label,
    minHeight,
    onPress,
    stretch = false,
    style,
    textStyle,
    tone = 'secondary',
    verticalPadding = 10,
  } = props;

  return (
    <Link href={href} asChild>
      <Pressable
        accessibilityLabel={accessibilityLabel}
        accessibilityHint={accessibilityHint}
        accessibilityRole='button'
        onPress={onPress}
        style={[
          getButtonContainerStyle({
            borderRadius,
            centered,
            minHeight,
            stretch,
            tone,
            verticalPadding,
          }),
          style,
        ]}
      >
        <Text style={[getButtonTextStyle(centered, tone, stretch), textStyle]}>{label}</Text>
      </Pressable>
    </Link>
  );
}

export function KangurMobilePendingActionButton(
  props: KangurMobilePendingActionButtonProps,
): React.JSX.Element {
  const {
    accessibilityLabel,
    horizontalPadding,
    label,
    onPress,
    pending,
    pendingLabel,
    stretch = false,
    verticalPadding = 10,
  } = props;

  return (
    <KangurMobileActionButton
      accessibilityLabel={accessibilityLabel}
      disabled={pending}
      disabledOpacity={1}
      horizontalPadding={horizontalPadding}
      label={pending ? pendingLabel : label}
      onPress={onPress}
      stretch={stretch}
      style={{
        backgroundColor: pending ? '#94a3b8' : '#1d4ed8',
      }}
      tone='brand'
      verticalPadding={verticalPadding}
    />
  );
}

import { Link, type Href } from 'expo-router';
import {
  Pressable,
  Text,
  View,
  type StyleProp,
  type TextStyle,
  type ViewStyle,
} from 'react-native';

export type KangurMobileTone = {
  backgroundColor: string;
  borderColor: string;
  textColor: string;
};

type KangurMobilePillProps = {
  label: string;
  tone: KangurMobileTone;
  style?: StyleProp<ViewStyle>;
  textStyle?: StyleProp<TextStyle>;
};

type KangurMobileMetricProps = {
  description: string;
  label: string;
  value: string;
  style?: StyleProp<ViewStyle>;
};

type KangurMobileFilterChipProps = {
  accessibilityLabel?: string;
  borderRadius?: number;
  centered?: boolean;
  href?: Href;
  fullWidth?: boolean;
  horizontalPadding?: number;
  idleTextColor?: string;
  label: string;
  minHeight?: number;
  onPress?: () => void;
  selectedBackgroundColor?: string;
  selectedBorderColor?: string;
  selectedTextColor?: string;
  selected: boolean;
  style?: StyleProp<ViewStyle>;
  textStyle?: StyleProp<TextStyle>;
  verticalPadding?: number;
};

type KangurMobileSectionTitleProps = {
  subtitle: string;
  title: string;
};

type KangurMobileSummaryChipProps = {
  backgroundColor?: string;
  borderColor?: string;
  label: string;
  textColor?: string;
};

type KangurMobileMutedActionChipProps = {
  compact?: boolean;
  label: string;
  style?: StyleProp<ViewStyle>;
  textStyle?: StyleProp<TextStyle>;
};

const KANGUR_MOBILE_INSET_METRIC_STYLE: ViewStyle = {
  borderRadius: 20,
  borderWidth: 1,
  borderColor: '#e2e8f0',
  backgroundColor: '#f8fafc',
  padding: 14,
  gap: 6,
};

export function KangurMobilePill(props: KangurMobilePillProps): React.JSX.Element {
  const { label, tone, style, textStyle } = props;

  return (
    <View
      style={[
        {
          alignSelf: 'flex-start',
          borderRadius: 999,
          borderWidth: 1,
          borderColor: tone.borderColor,
          backgroundColor: tone.backgroundColor,
          paddingHorizontal: 12,
          paddingVertical: 7,
        },
        style,
      ]}
    >
      <Text style={[{ color: tone.textColor, fontSize: 12, fontWeight: '700' }, textStyle]}>
        {label}
      </Text>
    </View>
  );
}

export function KangurMobileMetric(props: KangurMobileMetricProps): React.JSX.Element {
  const { description, label, value, style } = props;

  return (
    <View style={[KANGUR_MOBILE_INSET_METRIC_STYLE, { flexBasis: '48%' }, style]}>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{label}</Text>
      <Text style={{ color: '#0f172a', fontSize: 22, fontWeight: '800' }}>{value}</Text>
      <Text style={{ color: '#475569', fontSize: 12, lineHeight: 18 }}>{description}</Text>
    </View>
  );
}

const getFilterChipContainerStyle = ({
  fullWidth,
  borderRadius,
  selected,
  selectedBorderColor,
  selectedBackgroundColor,
  centered,
  minHeight,
  horizontalPadding,
  verticalPadding,
}: {
  fullWidth: boolean;
  borderRadius: number;
  selected: boolean;
  selectedBorderColor: string;
  selectedBackgroundColor: string;
  centered: boolean;
  minHeight?: number;
  horizontalPadding: number;
  verticalPadding: number;
}): ViewStyle => ({
  alignSelf: fullWidth ? 'stretch' : 'flex-start',
  width: fullWidth ? '100%' : undefined,
  borderRadius,
  borderWidth: 1,
  borderColor: selected ? selectedBorderColor : '#cbd5e1',
  backgroundColor: selected ? selectedBackgroundColor : '#ffffff',
  alignItems: centered ? 'center' : undefined,
  justifyContent: centered ? 'center' : undefined,
  minHeight,
  paddingHorizontal: horizontalPadding,
  paddingVertical: verticalPadding,
});

const getFilterChipTextStyle = ({
  selected,
  selectedTextColor,
  idleTextColor,
  centered,
  fullWidth,
}: {
  selected: boolean;
  selectedTextColor: string;
  idleTextColor: string;
  centered: boolean;
  fullWidth: boolean;
}): TextStyle => ({
  color: selected ? selectedTextColor : idleTextColor,
  fontSize: 13,
  fontWeight: '700',
  textAlign: (centered || fullWidth) ? 'center' : 'left',
});

const resolveFilterChipContent = (
  props: Pick<KangurMobileFilterChipProps, 'accessibilityLabel' | 'label' | 'onPress' | 'style'>,
  chipStyle: ViewStyle,
  chipTextStyle: TextStyle,
  textStyle?: StyleProp<TextStyle>,
): React.JSX.Element => (
  <Pressable
    accessibilityLabel={props.accessibilityLabel}
    accessibilityRole='button'
    onPress={props.onPress}
    style={[chipStyle, props.style]}
  >
    <Text style={[chipTextStyle, textStyle]}>{props.label}</Text>
  </Pressable>
);

export function KangurMobileFilterChip(
  props: KangurMobileFilterChipProps,
): React.JSX.Element {
  const {
    borderRadius = 999,
    centered = false,
    href,
    fullWidth = false,
    horizontalPadding = 14,
    idleTextColor = '#334155',
    selected,
    selectedBackgroundColor = '#dbeafe',
    selectedBorderColor = '#1d4ed8',
    selectedTextColor = '#1d4ed8',
    textStyle,
    verticalPadding = 10,
  } = props;

  const chipStyle = getFilterChipContainerStyle({
    fullWidth,
    borderRadius,
    selected,
    selectedBorderColor,
    selectedBackgroundColor,
    centered,
    minHeight: props.minHeight,
    horizontalPadding,
    verticalPadding,
  });

  const chipTextStyle = getFilterChipTextStyle({
    selected,
    selectedTextColor,
    idleTextColor,
    centered,
    fullWidth,
  });

  const content = resolveFilterChipContent(props, chipStyle, chipTextStyle, textStyle);

  if (href !== undefined) {
    return (
      <Link href={href} asChild>
        {content}
      </Link>
    );
  }

  return content;
}

export function KangurMobileSectionTitle(
  props: KangurMobileSectionTitleProps,
): React.JSX.Element {
  const { subtitle, title } = props;

  return (
    <View style={{ gap: 6 }}>
      <Text style={{ color: '#0f172a', fontSize: 28, fontWeight: '800' }}>{title}</Text>
      <Text style={{ color: '#475569', fontSize: 15, lineHeight: 22 }}>{subtitle}</Text>
    </View>
  );
}

export function KangurMobileSummaryChip(
  props: KangurMobileSummaryChipProps,
): React.JSX.Element {
  const {
    backgroundColor = '#eef2ff',
    borderColor = '#c7d2fe',
    label,
    textColor = '#4338ca',
  } = props;

  return (
    <View
      style={{
        alignSelf: 'flex-start',
        borderRadius: 999,
        borderWidth: 1,
        borderColor,
        backgroundColor,
        paddingHorizontal: 12,
        paddingVertical: 7,
      }}
    >
      <Text style={{ color: textColor, fontSize: 12, fontWeight: '700' }}>{label}</Text>
